import{_ as a,o as i,c,ag as t}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Bí Danh Rust | Dotfiles (VI)","titleTemplate":":title","description":"Lệnh Rust rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","frontmatter":{"title":"Bí Danh Rust | Dotfiles","description":"Lệnh Rust rút gọn. Tổng quan cho Dotfiles v0.2.495. Tương thích với macOS, Linux và WSL qua Dotfiles.","lang":"vi-VN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Bí Danh Rust | Dotfiles preview","canonical":"/vi/aliases/rust/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Bí danh Rust","pageType":"docs","schemaType":"WebPage","permalink":"/vi/aliases/rust/"},"headers":[],"relativePath":"vi/aliases/rust/index.md","filePath":"vi/aliases/rust/index.md","lastUpdated":1773010926000}'),o={name:"vi/aliases/rust/index.md"};function n(d,e,l,h,r,u){return i(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="bi-danh-rust" tabindex="-1">Bí Danh Rust <a class="header-anchor" href="#bi-danh-rust" aria-label="Permalink to &quot;Bí Danh Rust&quot;">​</a></h1><p>Lệnh Rust rút gọn.</p><p>Trang này giới thiệu một nhóm bí danh và các phím tắt lệnh thường dùng. Đọc trang này trước để hiểu quy ước đặt tên, đầu vào mong đợi và mẫu thực thi an toàn. Sau đó mở phụ lục tham khảo để xem toàn bộ danh sách lệnh và cú pháp chính xác. Các bí danh này giảm việc gõ lặp lại và duy trì hành vi quy trình làm việc nhất quán trên macOS, Linux và WSL.</p><h2 id="khi-nao-su-dung" tabindex="-1">Khi Nào Sử Dụng <a class="header-anchor" href="#khi-nao-su-dung" aria-label="Permalink to &quot;Khi Nào Sử Dụng&quot;">​</a></h2><p>Sử dụng trang này trước công việc shell hàng ngày khi bạn cần mẫu lệnh dự đoán được.</p><h2 id="bao-gom" tabindex="-1">Bao Gồm <a class="header-anchor" href="#bao-gom" aria-label="Permalink to &quot;Bao Gồm&quot;">​</a></h2><ul><li>Bí danh: 75</li><li>Hàm hỗ trợ: 0</li><li>Tệp nguồn: 1</li></ul><h2 id="vi-du-nhanh" tabindex="-1">Ví Dụ Nhanh <a class="header-anchor" href="#vi-du-nhanh" aria-label="Permalink to &quot;Ví Dụ Nhanh&quot;">​</a></h2><ul><li><code>cg</code> → <code>&#39;cargo&#39; # Phím tắt Cargo</code></li><li><code>cga</code> → <code>&#39;cg add&#39; # Thêm phụ thuộc</code></li><li><code>cgad</code> → <code>&#39;cg add --dev&#39; # Thêm phụ thuộc dev</code></li><li><code>cgaud</code> → <code>&#39;cg audit&#39; # Kiểm tra lỗ hổng bảo mật</code></li><li><code>cgb</code> → <code>&#39;cg build&#39; # Build debug</code></li><li><code>cgba</code> → <code>&#39;cg build --all-targets&#39; # Build tất cả target</code></li><li><code>cgbh</code> → <code>&#39;cg bench&#39; # Chạy benchmark</code></li><li><code>cgbl</code> → <code>&#39;cg bloat&#39; # Phân tích kích thước binary</code></li><li><code>cgbp</code> → <code>&#39;cg build --release --profile&#39; # Build với profile cụ thể</code></li><li><code>cgbr</code> → <code>&#39;cg build --release&#39; # Build release</code></li><li><code>cgbt</code> → <code>&#39;cg build --all-features&#39; # Build với tất cả tính năng</code></li><li><code>cgc</code> → <code>&#39;cg check&#39; # Kiểm tra biên dịch</code></li></ul><h2 id="buoc-tiep-theo" tabindex="-1">Bước Tiếp Theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước Tiếp Theo&quot;">​</a></h2><p>Mở danh sách đầy đủ:</p>',11)])])}const m=a(o,[["render",n]]);export{g as __pageData,m as default};
